   128→	// If this is an alpha tag, don't remove by default, but allow the option.
   129→	// If the cluster-admin has requested serving one more release, allow it.
   130→	if e.isAlpha && e.strictRemovedHandlingInAlpha { // don't serve in alpha if we want strict handling
   131→		return false
   132→	}
